import React, { useEffect, useRef } from "react";
import { MapContainer, TileLayer, Marker, useMap } from "react-leaflet";
import L from "leaflet";
import "leaflet/dist/leaflet.css";
import "leaflet-routing-machine";

/* FIX ICON */
delete L.Icon.Default.prototype._getIconUrl;

L.Icon.Default.mergeOptions({
  iconRetinaUrl:
    "https://unpkg.com/leaflet@1.9.4/dist/images/marker-icon-2x.png",
  iconUrl:
    "https://unpkg.com/leaflet@1.9.4/dist/images/marker-icon.png",
  shadowUrl:
    "https://unpkg.com/leaflet@1.9.4/dist/images/marker-shadow.png"
});

/* ROUTING */
function Routing({ origin, destination, setInfo }) {
  const map = useMap();
  const routingRef = useRef(null);

  useEffect(() => {
    if (!origin || !destination) return;

    if (routingRef.current) {
      map.removeControl(routingRef.current);
    }

    routingRef.current = L.Routing.control({
      waypoints: [
        L.latLng(origin.lat, origin.lon),
        L.latLng(destination.lat, destination.lon)
      ],
      lineOptions: {
        styles: [{ color: "#1a73e8", weight: 6 }]
      },
      addWaypoints: false,
      draggableWaypoints: false,
      routeWhileDragging: false,
      show: false
    })
      .on("routesfound", function (e) {
        const route = e.routes[0];

        const distance = (route.summary.totalDistance / 1000).toFixed(2);
        const time = (route.summary.totalTime / 60).toFixed(0);

        setInfo({ distance, time });
      })
      .addTo(map);

  }, [origin, destination]);

  return null;
}

function MapView({ origin, destination, setInfo }) {

  if (!origin) return <p>📍 Getting location...</p>;

  return (
    <div style={{ height: "450px", width: "100%" }}>
      <MapContainer
        center={[origin.lat, origin.lon]}
        zoom={14}
        style={{ height: "100%", width: "100%" }}
      >
        <TileLayer url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png" />

        <Marker position={[origin.lat, origin.lon]} />

        {destination && (
          <Marker position={[destination.lat, destination.lon]} />
        )}

        {destination && (
          <Routing
            origin={origin}
            destination={destination}
            setInfo={setInfo}
          />
        )}
      </MapContainer>
    </div>
  );
}

export default MapView;
